/// <summary>
///
/// </summary>
public void postLoad()
{
    super();
    this.VendName = VendTable::find(this.VendAccount).name();
    Ledger          ledger;
    DataArea        dataArea;
    DirOrganization     dirorganization;
    str                 countryRegionId,countryRegionIdname;

    select firstonly RecId from dataArea where dataArea.id == curExt();

    //..
    select firstonly dirorganization
        where dirorganization.RecId == VendTable::find(this.VendAccount).Party;

    countryRegionId  = VendTable::find(this.VendAccount).countryRegionId();

    countryRegionIdname  = LogisticsAddressCountryRegionTranslation::find(countryRegionId).ShortName;

    this.VendorOrganizationNumber   =  dirorganization.OrgNumber;
    this.VendorCountryRegionName    = countryRegionIdname;

    //addedd fileds


    ledger = Ledger::findByLegalEntity(dataArea.Recid);



    ETG_purchTableTrade ETG_purchTableTrade;

    select firstonly  ETG_purchTableTrade
        where ETG_purchTableTrade.purchId == this.purchId;


    this.CommOrig       = InventDim::find(this.InventDimId).InventColorId;// ETG_purchTableTrade.CountryOfOriginOfGoods;
    this.purchdestCountry = ETG_purchTableTrade.CountryOfFinalDestination;

    ExchangeRateUnionView ExchangeRateUnionView, ExchangeRateUnionViewLoc;
    select firstonly ExchangeRateUnionView
        order by ExchangeRateUnionView.ValidFrom desc
        where ExchangeRateUnionView.FromCurrencyCode == this.CurrencyCode && ExchangeRateUnionView.ToCurrencyCode == 'USD'
        && ExchangeRateUnionView.ValidFrom <= DateTimeUtil::date(this.CreatedDateTime) &&  ExchangeRateUnionView.ValidTo >= DateTimeUtil::date(this.CreatedDateTime);
    AmountMST AmtUSD;
    if (this.CurrencyCode == 'USD')
    {
        this.AmountinUSD = 1*this.LineAmount;
        AmtUSD = 1*this.LineAmount;
        this.ExchInUSD = 1;
    }
    else
    {
        this.AmountinUSD = ExchangeRateUnionView.ExchangeRate*this.LineAmount;
        AmtUSD =  ExchangeRateUnionView.ExchangeRate*this.LineAmount;
        this.ExchInUSD = ExchangeRateUnionView.ExchangeRate/100.00;
    }



    select firstonly  ExchangeRateUnionViewLoc
        order by ExchangeRateUnionViewLoc.ValidFrom desc
  where ExchangeRateUnionViewLoc.FromCurrencyCode == this.CurrencyCode && ExchangeRateUnionViewLoc.ToCurrencyCode == Ledger::accountingCurrency(CompanyInfo::current())
  && ExchangeRateUnionViewLoc.ValidFrom <= DateTimeUtil::date(this.CreatedDateTime) &&  ExchangeRateUnionViewLoc.ValidTo >= DateTimeUtil::date(this.CreatedDateTime);





    if (this.CurrencyCode == Ledger::accountingCurrency(CompanyInfo::current() ))
    {
        this.AmountinLC = 1*this.LineAmount;
        this.ExchInLC   = 1;
    }
    else

    {
        this.AmountinLC = ExchangeRateUnionViewLoc.ExchangeRate*this.LineAmount;
        this.ExchInLC = (ExchangeRateUnionViewLoc.ExchangeRate)/100.00;
    }

    this.CurrecyLC      = Ledger::accountingCurrency();

    ETGACFParameters aCFParameters = ETGACFParameters::find();

    this.Vertical     = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValue(this.DefaultDimension, aCFParameters.Vertical);
    //this.SubVertical  = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValue(this.DefaultDimension, "BusinessUnit");


    DefaultDimensionView DefaultDimensionView;
    select * from DefaultDimensionView where DefaultDimensionView.DEFAULTDIMENSION == this.DefaultDimension
        && DefaultDimensionView.Name == aCFParameters.SubVertical;

    DimAttributeOMBusinessUnit dimAttributeOMBusinessUnit;

    select * from dimAttributeOMBusinessUnit
        where dimAttributeOMBusinessUnit.value == DefaultDimensionView.DisplayValue;


    if (dimAttributeOMBusinessUnit)
    {
        this.SubVertical            = dimAttributeOMBusinessUnit.Name;
    }


    this.Commodity    = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValue(this.DefaultDimension, aCFParameters.MainCommodity);
    this.SubCommodity = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValue(this.DefaultDimension, aCFParameters.SubCommodity);
  //  this.ItemDIm        = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValue(this.DefaultDimension, aCFParameters.ItemId);

    if (this.PurchQty == 0 )
    {
        this.PurchasePriceMT = 0;
    }
    else
    {
        this.PurchasePriceMT = AmtUSD/this.PurchQty;
    }

    select firstonly  Name from dataArea
        where dataArea.id       == this.DataAreaId;

    this.EntityName             = dataArea.name;

    UnitOfMeasure FromunitOfMeasure = UnitOfMeasure::findBySymbol(this.purchUnit);
    UnitOfMeasure TounitOfMeasure = UnitOfMeasure::findBySymbol('MT');

    if (FromunitOfMeasure == TounitOfMeasure)
    {
        this.ExchMT = 1;
    }
    else
    {
        this.ExchMT = UnitOfMeasureConversion::findByConversion(FromunitOfMeasure.RecId,TounitOfMeasure.RecId ).Factor;
    }


    this.DlvHeader = PurchTable::find(this.PurchId).DlvTerm;
    this.Invoicedate = VendInvoiceJour::findFromPurchId(this.PurchId).InvoiceDate;


    LogisticsAddressCountryRegionId regid = CompanyInfo::find().postalAddress().CountryRegionId;

    LanguageIdAll langid = currentUserLanguage();


    LogisticsAddressCountryRegionTranslation logisticsAddressCountryRegionTranslation;


    select * from logisticsAddressCountryRegionTranslation where logisticsAddressCountryRegionTranslation.CountryRegionId == regid && logisticsAddressCountryRegionTranslation.CountryRegionId == langid;

    this.CompanyCountry = logisticsAddressCountryRegionTranslation.LongName;

    DirPartyTable dirPartyTable;

    VendTable vendtableLoc;

    select firstonly Party from vendtableLoc where vendtableLoc.AccountNum == this.VendAccount;

    select firstonly KnownAs from dirPartyTable where dirPartyTable.recid == vendtableLoc.Party;




    this.EntityStdName = dirPartyTable.KnownAs;
    this.GroupCompName  = VendTable::find(this.VendAccount).organizationNumber();
    this.CompanyCountry = VendTable::find(this.VendAccount).countryRegionName();
    this.ItemDim = EcoResProductTranslation::findByProductLanguage(InventTable::find(this.ItemId).Product, SystemParameters::getSystemLanguageId()).Name;

    this.ItemDim = EcoResProductTranslation::findByProductLanguage(InventTable::find(this.ItemId).Product, SystemParameters::getSystemLanguageId()).Name;
    DimensionAttributeValue dimAttributeValue;
    DefaultDimensionView dimensionView;
    DimensionAttribute dimensionAttribute;
    select firstOnly dimensionView
        where dimensionView.DefaultDimension == this.DefaultDimension
        join dimensionAttribute
        where dimensionView.Name == aCFParameters.ItemId;

    this.ItemDim = EcoResProductTranslation::findByProductLanguage(InventTable::find(dimensionView.DisplayValue).Product, SystemParameters::getSystemLanguageId()).Name;





    this.ItemDesc = EcoResProductTranslation::findByProductLanguage(InventTable::find(this.ItemId).Product, SystemParameters::getSystemLanguageId()).Name;


}
